1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Result = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	const COMPONENT_UNIT_PRICE = 25;
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
25	
26	const roundPremium = (amount: number): number => Math.ceil(amount);
27	
28	const priceForComponentCount = (count: number): number => {
29	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
30	  const leftovers = count % COMPONENT_BLOCK_SIZE;
31	  return blocks * COMPONENT_BLOCK_PRICE + leftovers * COMPONENT_UNIT_PRICE;
32	};
33	
34	const sumComponentBase = (componentCountsByType: Map<string, number>): number => {
35	  let total = 0;
36	  for (const count of componentCountsByType.values()) {
37	    total += priceForComponentCount(count);
38	  }
39	  return total;
40	};
41	
42	const baseForItems = (items: Item[]): number => {
43	  const componentCountsByType = new Map<string, number>();
44	  let nonComponentBase = 0;
45	  for (const item of items) {
46	    if (isComponent(item)) {
47	      componentCountsByType.set(item.type, (componentCountsByType.get(item.type) ?? 0) + 1);
48	    } else {
49	      nonComponentBase += basePremiumFor(item);
50	    }
51	  }
52	  return nonComponentBase + sumComponentBase(componentCountsByType);
53	};
54	
55	const quotePremium = (items: Item[]): number => {
56	  const base = baseForItems(items);
57	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
58	  return roundPremium(base + firstInsuranceSurcharge + PROCESSING_FEE);
59	};
60	
61	export const runScenario = (input: {
62	  customer: { yearsWithMHPCO: number };
63	  steps: Step[];
64	}): { results: Result[] } => {
65	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
66	  return { results };
67	};
